class Depth:
    """Depth prior attached to an Observation."""

    def __init__(self, value: float, is_radial: bool, std_deviation: float):
        self.value         = float(value)
        self.is_radial     = bool(is_radial)
        self.std_deviation = float(std_deviation)

    def __repr__(self):
        return (f"Depth(value={self.value}, is_radial={self.is_radial}, "
                f"std_deviation={self.std_deviation})")


# ---------------------------------------------------------------------------
# Observation
# ---------------------------------------------------------------------------

class Observation:
    """One feature observation in one image."""

    NO_SEMANTIC_VALUE: int = -1

    def __init__(
        self,
        x: float, y: float, s: float,
        r: int, g: int, b: int,
        feature: int,
        segmentation: int = -1,
        instance: int = -1,
    ):
        self.point       = np.array([x, y], dtype=np.float64)
        self.scale       = float(s)
        self.color       = np.array([r, g, b], dtype=np.int32)
        self.id          = int(feature)        # feature_id
        self.segmentation = int(segmentation)
        self.instance    = int(instance)
        self.depth_prior: Optional[Depth] = None

    def copy(self) -> "Observation":
        obs = Observation(
            self.point[0], self.point[1], self.scale,
            int(self.color[0]), int(self.color[1]), int(self.color[2]),
            self.id, self.segmentation, self.instance,
        )
        obs.depth_prior = copy.copy(self.depth_prior)
        return obs

    def __repr__(self):
        return (f"Observation(point={self.point}, scale={self.scale}, "
                f"color={self.color}, id={self.id})")


# ---------------------------------------------------------------------------
# ShotMeasurement (generic optional-value wrapper)
# ---------------------------------------------------------------------------

class _ShotMeasurement:
    """Generic optional-value container — mirrors OptionalValue<T>."""

    def __init__(self):
        self._has_value = False
        self._value     = None

    @property
    def has_value(self) -> bool:
        return self._has_value

    @property
    def value(self):
        if not self._has_value:
            raise RuntimeError("ShotMeasurement has no value")
        return self._value

    @value.setter
    def value(self, v):
        self._value     = v
        self._has_value = True

    def reset(self):
        self._has_value = False
        self._value     = None

    def __repr__(self):
        return f"{self.__class__.__name__}(has_value={self._has_value}, value={self._value})"


class ShotMeasurementInt(_ShotMeasurement):
    pass

class ShotMeasurementDouble(_ShotMeasurement):
    pass

class ShotMeasurementVec3d(_ShotMeasurement):
    pass

class ShotMeasurementString(_ShotMeasurement):
    pass


# ---------------------------------------------------------------------------
# ShotMeasurements
# ---------------------------------------------------------------------------

class ShotMeasurements:
    """Bundle of optional per-shot metadata."""

    def __init__(self):
        self.gps_accuracy    = ShotMeasurementDouble()
        self.gps_position    = ShotMeasurementVec3d()
        self.orientation     = ShotMeasurementInt()
        self.capture_time    = ShotMeasurementDouble()
        self.gravity_down    = ShotMeasurementVec3d()
        self.compass_angle   = ShotMeasurementDouble()
        self.compass_accuracy = ShotMeasurementDouble()
        self.opk_angles      = ShotMeasurementVec3d()
        self.opk_accuracy    = ShotMeasurementDouble()
        self.sequence_key    = ShotMeasurementString()
        self._attributes: dict = {}

    def get_attributes(self) -> dict:
        return self._attributes

    def set_attributes(self, attrs: dict):
        self._attributes = dict(attrs)

    attributes = property(get_attributes, set_attributes)

    def set(self, other: "ShotMeasurements"):
        """Copy all values from another ShotMeasurements."""
        for field in ("gps_accuracy", "gps_position", "orientation",
                      "capture_time", "gravity_down", "compass_angle",
                      "compass_accuracy", "opk_angles", "opk_accuracy",
                      "sequence_key"):
            src = getattr(other, field)
            dst = getattr(self, field)
            if src.has_value:
                dst.value = copy.deepcopy(src.value)
            else:
                dst.reset()
        self._attributes = copy.deepcopy(other._attributes)

    def __copy__(self):
        new = ShotMeasurements()
        new.set(self)
        return new


