class RigCamera:
    def __init__(self, pose=None, id: str = ""):
        self.id   = id
        self.pose = pose if pose is not None else _make_default_pose()

    def __repr__(self):
        return f"RigCamera(id={self.id!r})"


# ---------------------------------------------------------------------------
# RigInstance
# ---------------------------------------------------------------------------

class RigInstance:
    def __init__(self, instance_id):
        self.id            = instance_id
        self._shots:       Dict[str, "Shot"]     = {}
        self._rig_cameras: Dict[str, RigCamera]  = {}
        self.pose = _make_default_pose()   # ← không còn None

    def get_shots(self) -> Dict[str, "Shot"]:
        return self._shots

    def get_rig_cameras(self) -> Dict[str, RigCamera]:
        return self._rig_cameras

    shots       = property(get_shots)
    rig_cameras = property(get_rig_cameras)

    def keys(self) -> List[str]:
        return list(self._shots.keys())

    def add_shot(self, shot_id: str, shot: "Shot"):
        self._shots[shot_id] = shot

    def remove_shot(self, shot_id: str):
        self._shots.pop(shot_id, None)

    def update_instance_pose_with_shot(self, shot_id: str, pose):
        if pose is not None:
            self.pose = copy.copy(pose)
        elif self.pose is None:
            self.pose = _make_default_pose()

    def update_rig_camera_pose(self, rig_camera_id: str, pose):
        if rig_camera_id in self._rig_cameras:
            self._rig_cameras[rig_camera_id].pose = copy.copy(pose)

    @property
    def rig_camera_ids(self) -> Dict[str, str]:
        return {sid: rc.id for sid, rc in self._rig_cameras.items()}

    @property
    def camera_ids(self) -> Dict[str, str]:
        return {sid: shot.camera.id
                for sid, shot in self._shots.items()
                if shot.camera is not None}

    def __repr__(self):
        return f"RigInstance(id={self.id!r}, shots={list(self._shots.keys())})"


# ---------------------------------------------------------------------------
# Shot
# ---------------------------------------------------------------------------

class Shot:
    def __init__(self, shot_id: str, camera=None, rig_instance: Optional[RigInstance] = None,
                 rig_camera: Optional[RigCamera] = None, pose=None):
        self.id           = shot_id
        self.camera       = camera
        self._rig_instance = rig_instance
        self._rig_camera   = rig_camera
        self.pose         = pose
        self.mesh         = ShotMesh()
        self._metadata    = ShotMeasurements()
        self._covariance: Optional[np.ndarray] = None
        self.merge_cc     = 0
        self.scale        = 1.0
        # landmark_id -> (Observation, Landmark)
        self._landmark_observations: Dict[str, Tuple[Observation, "Landmark"]] = {}

    # --- rig accessors -------------------------------------------------------

    def get_rig_instance(self) -> Optional[RigInstance]:
        return self._rig_instance

    def get_rig_camera(self) -> Optional[RigCamera]:
        return self._rig_camera

    @property
    def rig_instance_id(self):
        return self._rig_instance.id if self._rig_instance else None

    @property
    def rig_camera_id(self):
        return self._rig_camera.id if self._rig_camera else None
    
    @property
    def rig_camera(self):
        return self._rig_camera

    @property  
    def rig_instance(self):
        return self._rig_instance

    def set_rig(self, rig_instance: RigInstance, rig_camera: RigCamera):
        self._rig_instance = rig_instance
        self._rig_camera   = rig_camera

    # --- metadata / pose -----------------------------------------------------

    @property
    def metadata(self) -> ShotMeasurements:
        return self._metadata

    @metadata.setter
    def metadata(self, v: ShotMeasurements):
        self._metadata = v

    @property
    def covariance(self):
        return self._covariance

    @covariance.setter
    def covariance(self, v):
        self._covariance = v

    # --- observations --------------------------------------------------------

    def create_observation(self, landmark: "Landmark", obs: Observation):
        self._landmark_observations[landmark.id] = (obs, landmark)

    def get_observation(self, feature_id: int) -> Optional[Observation]:
        for obs, lm in self._landmark_observations.values():
            if obs.id == feature_id:
                return obs
        return None

    def get_landmark_observation(self, landmark: "Landmark") -> Optional[Observation]:
        entry = self._landmark_observations.get(landmark.id)
        return entry[0] if entry else None

    def get_observation_landmark(self, feature_id: int) -> Optional["Landmark"]:
        for obs, lm in self._landmark_observations.values():
            if obs.id == feature_id:
                return lm
        return None

    def remove_landmark_observation(self, feature_id: int):
        to_del = [lid for lid, (obs, _) in self._landmark_observations.items()
                  if obs.id == feature_id]
        for lid in to_del:
            del self._landmark_observations[lid]

    def get_landmark_observations(self) -> Dict["Landmark", int]:
        return {lm: obs.id for obs, lm in self._landmark_observations.values()}

    def compute_valid_landmarks(self) -> List["Landmark"]:
        return [lm for _, lm in self._landmark_observations.values()]

    # --- projection (delegates to camera) ------------------------------------

    def project(self, point3d: np.ndarray) -> np.ndarray:
        if self.camera is None or self.pose is None:
            raise RuntimeError("Shot has no camera or pose")
        return self.camera.project(self.pose.transform(point3d))

    def project_many(self, points3d: np.ndarray) -> np.ndarray:
        return np.array([self.project(p) for p in points3d])

    def bearing(self, point2d: np.ndarray) -> np.ndarray:
        if self.camera is None:
            raise RuntimeError("Shot has no camera")
        return self.camera.bearing(point2d)

    def bearing_many(self, points2d: np.ndarray) -> np.ndarray:
        return np.array([self.bearing(p) for p in points2d])

    def __repr__(self):
        return f"Shot(id={self.id!r})"


# ---------------------------------------------------------------------------
# Landmark
# ---------------------------------------------------------------------------

class Landmark:
    def __init__(self, landmark_id: str, coordinates: np.ndarray):
        self.id                   = landmark_id
        self._coordinates         = np.array(coordinates, dtype=np.float64)
        self.color                = np.zeros(3, dtype=np.int32)
        self.reprojection_errors: Dict[str, np.ndarray] = {}
        # shot -> feature_id
        self._observations: Dict[Shot, int] = {}

    @property
    def coordinates(self) -> np.ndarray:
        return self._coordinates

    @coordinates.setter
    def coordinates(self, v: np.ndarray):
        self._coordinates = np.array(v, dtype=np.float64)

    def get_global_pos(self) -> np.ndarray:
        return self._coordinates

    def set_global_pos(self, pos: np.ndarray):
        self._coordinates = np.array(pos, dtype=np.float64)

    def add_observation(self, shot: Shot, feature_id: int):
        self._observations[shot] = feature_id

    def remove_observation(self, shot: Shot):
        self._observations.pop(shot, None)

    def get_observations(self) -> Dict[Shot, int]:
        return self._observations

    def number_of_observations(self) -> int:
        return len(self._observations)

    def get_observation_id_in_shot(self, shot: Shot) -> Optional[int]:
        return self._observations.get(shot)

    def clear_observations(self):
        self._observations.clear()

    def __repr__(self):
        return f"Landmark(id={self.id!r}, coords={self._coordinates})"


