class GroundControlPointObservation:
    def __init__(self, shot_id: Optional[str] = None,
                 projection: Optional[np.ndarray] = None):
        self.shot_id    = shot_id or ""
        self.projection = projection if projection is not None else np.zeros(2)
        self.uid        = 0


class GroundControlPoint:
    def __init__(self):
        self.id               = ""
        self.survey_point_id  = 0
        self.has_altitude     = False
        self.lla: Dict[str, float] = {}
        self._lla_vec         = np.zeros(3, dtype=np.float64)
        self.role             = GroundControlPointRole.OPTIMIZATION
        self._observations: List[GroundControlPointObservation] = []

    @property
    def lla_vec(self) -> np.ndarray:
        return self._lla_vec

    @lla_vec.setter
    def lla_vec(self, v: np.ndarray):
        self._lla_vec = np.array(v, dtype=np.float64)
        if len(v) >= 3:
            self.lla = {"latitude": v[0], "longitude": v[1], "altitude": v[2]}

    @property
    def observations(self) -> List[GroundControlPointObservation]:
        return self._observations

    @observations.setter
    def observations(self, v: List[GroundControlPointObservation]):
        self._observations = list(v)

    def add_observation(self, obs: GroundControlPointObservation):
        self._observations.append(obs)


# ---------------------------------------------------------------------------
# TracksManager
# ---------------------------------------------------------------------------

class TracksManager:
    """
    Manages the bipartite graph between shots and tracks (landmarks).
    Each cell is an Observation.
    """

    def __init__(self):
        # shot_id -> {track_id -> Observation}
        self._shot_to_obs:  Dict[str, Dict[str, Observation]] = {}
        # track_id -> {shot_id -> Observation}
        self._track_to_obs: Dict[str, Dict[str, Observation]] = {}

    # --- mutation ------------------------------------------------------------

    def add_observation(self, shot_id: str, track_id: str, obs: Observation):
        self._shot_to_obs.setdefault(shot_id, {})[track_id]  = obs
        self._track_to_obs.setdefault(track_id, {})[shot_id] = obs

    def remove_observation(self, shot_id: str, track_id: str):
        self._shot_to_obs.get(shot_id, {}).pop(track_id, None)
        self._track_to_obs.get(track_id, {}).pop(shot_id, None)

    # --- queries -------------------------------------------------------------

    def num_shots(self) -> int:
        return len(self._shot_to_obs)

    def num_tracks(self) -> int:
        return len(self._track_to_obs)

    def get_shot_ids(self) -> List[str]:
        return list(self._shot_to_obs.keys())

    def get_track_ids(self) -> List[str]:
        return list(self._track_to_obs.keys())

    def get_observation(self, shot_id: str, track_id: str) -> Observation:
        try:
            return self._shot_to_obs[shot_id][track_id]
        except KeyError:
            raise RuntimeError(f"No observation for shot={shot_id} track={track_id}")

    def get_shot_observations(self, shot_id: str) -> Dict[str, Observation]:
        if shot_id not in self._shot_to_obs:
            raise RuntimeError(f"Shot {shot_id!r} not in TracksManager")
        return dict(self._shot_to_obs[shot_id])

    def get_track_observations(self, track_id: str) -> Dict[str, Observation]:
        if track_id not in self._track_to_obs:
            raise RuntimeError(f"Track {track_id!r} not in TracksManager")
        return dict(self._track_to_obs[track_id])

    def get_all_pairs_connectivity(
        self,
        shots: Optional[List[str]] = None,
        tracks: Optional[List[str]] = None,
    ) -> Dict[Tuple[str, str], int]:
        """Return {(im1, im2): number_of_common_tracks}."""
        use_shots  = set(shots)  if shots  else set(self._shot_to_obs)
        use_tracks = set(tracks) if tracks else set(self._track_to_obs)

        pair_count: Dict[Tuple[str, str], int] = {}
        for track_id in use_tracks:
            shots_in_track = [s for s in self._track_to_obs.get(track_id, {})
                              if s in use_shots]
            for i in range(len(shots_in_track)):
                for j in range(i + 1, len(shots_in_track)):
                    a, b = sorted([shots_in_track[i], shots_in_track[j]])
                    pair_count[(a, b)] = pair_count.get((a, b), 0) + 1
        return pair_count

    def get_all_common_observations(
        self, im1: str, im2: str
    ) -> List[Tuple[str, Observation, Observation]]:
        """Return [(track_id, obs_in_im1, obs_in_im2), ...]."""
        obs1 = self._shot_to_obs.get(im1, {})
        obs2 = self._shot_to_obs.get(im2, {})
        result = []
        for track_id, o1 in obs1.items():
            if track_id in obs2:
                result.append((track_id, o1, obs2[track_id]))
        return result

    def construct_sub_tracks_manager(
        self, shots: List[str], tracks: List[str]
    ) -> "TracksManager":
        sub = TracksManager()
        shot_set  = set(shots)
        track_set = set(tracks)
        for shot_id in shot_set:
            for track_id, obs in self._shot_to_obs.get(shot_id, {}).items():
                if track_id in track_set:
                    sub.add_observation(shot_id, track_id, obs)
        return sub

    def write_to_file(self, path: str):
        import csv, io as _io
        with open(path, "w", newline="") as fout:
            writer = csv.writer(fout, delimiter="\t")
            for shot_id, tracks in self._shot_to_obs.items():
                for track_id, obs in tracks.items():
                    writer.writerow([
                        shot_id, track_id,
                        obs.id,
                        obs.point[0], obs.point[1],
                        obs.scale,
                        obs.color[0], obs.color[1], obs.color[2],
                        obs.segmentation, obs.instance,
                    ])

    def as_string(self) -> str:
        import io as _io, csv
        buf = _io.StringIO()
        writer = csv.writer(buf, delimiter="\t")
        for shot_id, tracks in self._shot_to_obs.items():
            for track_id, obs in tracks.items():
                writer.writerow([
                    shot_id, track_id, obs.id,
                    obs.point[0], obs.point[1], obs.scale,
                    obs.color[0], obs.color[1], obs.color[2],
                    obs.segmentation, obs.instance,
                ])
        return buf.getvalue()

    @staticmethod
    def instanciate_from_file(path: str) -> "TracksManager":
        import csv
        tm = TracksManager()
        with open(path, "r", newline="") as fin:
            for row in csv.reader(fin, delimiter="\t"):
                if len(row) < 11:
                    continue
                shot_id, track_id = row[0], row[1]
                obs = Observation(
                    float(row[3]), float(row[4]), float(row[5]),
                    int(row[6]), int(row[7]), int(row[8]),
                    int(row[2]),
                    int(row[9]), int(row[10]),
                )
                tm.add_observation(shot_id, track_id, obs)
        return tm

    @staticmethod
    def instanciate_from_string(data: str) -> "TracksManager":
        import csv, io as _io
        tm = TracksManager()
        for row in csv.reader(_io.StringIO(data), delimiter="\t"):
            if len(row) < 11:
                continue
            shot_id, track_id = row[0], row[1]
            obs = Observation(
                float(row[3]), float(row[4]), float(row[5]),
                int(row[6]), int(row[7]), int(row[8]),
                int(row[2]),
                int(row[9]), int(row[10]),
            )
            tm.add_observation(shot_id, track_id, obs)
        return tm

    @staticmethod
    def merge_tracks_manager(managers: List["TracksManager"]) -> "TracksManager":
        merged = TracksManager()
        for tm in managers:
            for shot_id, tracks in tm._shot_to_obs.items():
                for track_id, obs in tracks.items():
                    merged.add_observation(shot_id, track_id, obs)
        return merged

    def __repr__(self):
        return (f"TracksManager(shots={self.num_shots()}, "
                f"tracks={self.num_tracks()})")


# ---------------------------------------------------------------------------
# View helpers (read-only dict-like wrappers)
# ---------------------------------------------------------------------------

class _BaseView:
    def __init__(self, data: dict):
        self._data = data

    def __len__(self) -> int:
        return len(self._data)

    def __contains__(self, key) -> bool:
        return key in self._data

    def __getitem__(self, key):
        return self._data[key]

    def __iter__(self) -> Iterator:
        return iter(self._data)

    def get(self, key):
        return self._data.get(key)

    def items(self) -> Iterator:
        return iter(self._data.items())

    def keys(self) -> Iterator:
        return iter(self._data.keys())

    def values(self) -> Iterator:
        return iter(self._data.values())


class ShotView(_BaseView):
    pass

class PanoShotView(_BaseView):
    pass

class LandmarkView(_BaseView):
    pass

class CameraView(_BaseView):
    pass

class BiasView(_BaseView):
    pass

class RigCameraView(_BaseView):
    pass

class RigInstanceView(_BaseView):
    pass


# ---------------------------------------------------------------------------
# Map
# ---------------------------------------------------------------------------

class Map:
    """
    Central scene graph.
    Mirrors map::Map from map.cc / pymap.cc.
    """

    def __init__(self):
        self._cameras:       Dict[str, object]      = {}
        self._shots:         Dict[str, Shot]         = {}
        self._pano_shots:    Dict[str, Shot]         = {}
        self._landmarks:     Dict[str, Landmark]     = {}
        self._rig_cameras:   Dict[str, RigCamera]    = {}
        self._rig_instances: Dict[str, RigInstance]  = {}
        self._biases:        Dict[str, object]       = {}
        self._reference      = None

    # --- static deep copy ----------------------------------------------------

    @staticmethod
    def deep_copy(src: "Map", copy_observations: bool = True) -> "Map":
        dst = Map()
        dst._reference = copy.deepcopy(src._reference)

        for cam_id, cam in src._cameras.items():
            dst.create_camera(cam)

        for shot_id, shot in src._shots.items():
            dst._update_shot_with_rig(shot, is_panoshot=False)

        for shot_id, shot in src._pano_shots.items():
            dst._update_shot_with_rig(shot, is_panoshot=True)

        for lm_id, lm in src._landmarks.items():
            dst.create_landmark(lm_id, lm.get_global_pos())

        if copy_observations:
            for shot_id, shot in src._shots.items():
                for lm, feat_id in shot.get_landmark_observations().items():
                    obs = shot.get_landmark_observation(lm)
                    if obs:
                        dst.add_observation(shot_id, lm.id, obs.copy())

        for cam_id, bias in src._biases.items():
            dst._biases[cam_id] = copy.copy(bias)

        return dst

    # --- camera --------------------------------------------------------------

    def create_camera(self, camera) -> object:
        self._cameras[camera.id] = camera
        self._biases[camera.id]  = None   # placeholder for Similarity
        return self._cameras[camera.id]

    def get_camera(self, camera_id: str):
        if camera_id not in self._cameras:
            raise RuntimeError(f"Accessing invalid CameraId {camera_id}")
        return self._cameras[camera_id]

    def has_camera(self, camera_id: str) -> bool:
        return camera_id in self._cameras

    def get_camera_view(self) -> CameraView:
        return CameraView(self._cameras)

    def get_cameras(self) -> CameraView:
        return self.get_camera_view()

    # --- bias ----------------------------------------------------------------

    def set_bias(self, camera_id: str, transform):
        if camera_id not in self._biases:
            raise RuntimeError(f"Accessing invalid CameraID {camera_id}")
        self._biases[camera_id] = transform

    def get_bias(self, camera_id: str):
        if camera_id not in self._biases:
            raise RuntimeError(f"Accessing invalid CameraID {camera_id}")
        return self._biases[camera_id]

    def get_biases(self) -> BiasView:
        return BiasView(self._biases)

    # --- rig cameras ---------------------------------------------------------

    def create_rig_camera(self, rig_camera: RigCamera) -> RigCamera:
        if rig_camera.id in self._rig_cameras:
            raise RuntimeError(f"RigCamera {rig_camera.id} already exists.")
        self._rig_cameras[rig_camera.id] = rig_camera
        return self._rig_cameras[rig_camera.id]

    def has_rig_camera(self, rig_camera_id: str) -> bool:
        return rig_camera_id in self._rig_cameras

    def get_rig_camera(self, rig_camera_id: str) -> RigCamera:
        if rig_camera_id not in self._rig_cameras:
            raise RuntimeError(f"Accessing invalid RigCameraID {rig_camera_id}")
        return self._rig_cameras[rig_camera_id]

    # --- rig instances -------------------------------------------------------

    def create_rig_instance(self, instance_id) -> RigInstance:
        if instance_id in self._rig_instances:
            raise RuntimeError(f"RigInstance {instance_id} already exists.")
        ri = RigInstance(instance_id)
        self._rig_instances[instance_id] = ri
        return ri

    def update_rig_instance(self, other: RigInstance) -> RigInstance:
        if other.id not in self._rig_instances:
            raise RuntimeError("Rig instance does not exist.")
        self._rig_instances[other.id] = other
        return other

    def remove_rig_instance(self, instance_id):
        if instance_id not in self._rig_instances:
            raise RuntimeError("Rig instance does not exist.")
        del self._rig_instances[instance_id]

    def has_rig_instance(self, instance_id) -> bool:
        return instance_id in self._rig_instances

    def get_rig_instance(self, instance_id) -> RigInstance:
        if instance_id not in self._rig_instances:
            raise RuntimeError("Accessing invalid RigInstance index")
        return self._rig_instances[instance_id]

    # --- shots ---------------------------------------------------------------

    def _make_shot(self, shot_id: str, camera_id: str,
                   rig_camera_id: str, instance_id,
                   pose=None) -> Shot:
        camera       = self.get_camera(camera_id)
        rig_instance = self.get_rig_instance(instance_id)
        rig_camera   = self.get_rig_camera(rig_camera_id)
        return Shot(shot_id, camera, rig_instance, rig_camera, pose)

    def create_shot(
        self,
        shot_id: str,
        camera_id: str,
        rig_camera_id: str = None,
        instance_id: str = None,
        pose=None,
    ) -> Shot:
        rig_camera_id = rig_camera_id if rig_camera_id else camera_id
        instance_id = instance_id if instance_id else shot_id

        if rig_camera_id not in self._rig_cameras:
            self._rig_cameras[rig_camera_id] = RigCamera(id=rig_camera_id)

        if instance_id not in self._rig_instances:
            ri = RigInstance(instance_id)
            self._rig_instances[instance_id] = ri

        if shot_id in self._shots:
            raise RuntimeError(f"Shot {shot_id} already exists.")

        shot = self._make_shot(shot_id, camera_id, rig_camera_id, instance_id, pose)
        self._shots[shot_id] = shot

        return shot

    def remove_shot(self, shot_id: str):
        if shot_id not in self._shots:
            raise RuntimeError(f"Accessing invalid ShotID {shot_id}")
        shot = self._shots[shot_id]
        if shot.get_rig_instance():
            shot.get_rig_instance().remove_shot(shot_id)
        for lm in list(shot.get_landmark_observations().keys()):
            lm.remove_observation(shot)
        del self._shots[shot_id]

    def get_shot(self, shot_id: str) -> Shot:
        if shot_id not in self._shots:
            raise RuntimeError(f"Accessing invalid ShotID {shot_id}")
        return self._shots[shot_id]

    def has_shot(self, shot_id: str) -> bool:
        return shot_id in self._shots

    def update_shot(self, other_shot: Shot) -> Shot:
        if other_shot.id not in self._shots:
            raise RuntimeError(f"Shot {other_shot.id} does not exist.")
        self._update_shot_with_rig(other_shot, is_panoshot=False)
        shot = self._shots[other_shot.id]
        shot.merge_cc = other_shot.merge_cc
        shot.scale    = other_shot.scale
        shot.metadata.set(other_shot.metadata)
        shot.covariance = copy.copy(other_shot.covariance)
        return shot

    def get_shots(self) -> ShotView:
        return ShotView(self._shots)

    # --- pano shots ----------------------------------------------------------

    def create_pano_shot(self, shot_id: str, camera_id: str,
                         rig_camera_id: str, instance_id,
                         pose=None) -> Shot:
        if shot_id in self._pano_shots:
            raise RuntimeError(f"PanoShot {shot_id} already exists.")
        shot = self._make_shot(shot_id, camera_id, rig_camera_id, instance_id, pose)
        self._pano_shots[shot_id] = shot
        return shot

    def remove_pano_shot(self, shot_id: str):
        if shot_id not in self._pano_shots:
            raise RuntimeError(f"Accessing invalid ShotID {shot_id}")
        shot = self._pano_shots[shot_id]
        if shot.get_rig_instance():
            shot.get_rig_instance().remove_shot(shot_id)
        del self._pano_shots[shot_id]

    def get_pano_shot(self, shot_id: str) -> Shot:
        if shot_id not in self._pano_shots:
            raise RuntimeError(f"Accessing invalid PanoShotID {shot_id}")
        return self._pano_shots[shot_id]

    def has_pano_shot(self, shot_id: str) -> bool:
        return shot_id in self._pano_shots

    def update_pano_shot(self, other_shot: Shot) -> Shot:
        if other_shot.id not in self._pano_shots:
            raise RuntimeError(f"Pano shot {other_shot.id} does not exist.")
        self._update_shot_with_rig(other_shot, is_panoshot=True)
        return self._pano_shots[other_shot.id]

    def get_pano_shots(self) -> PanoShotView:
        return PanoShotView(self._pano_shots)

    # --- rig helper ----------------------------------------------------------

    def _update_shot_with_rig(self, other_shot: Shot, is_panoshot: bool):
        ri = other_shot.get_rig_instance()
        if ri is None:
            return
        instance_id = ri.id
        if not self.has_rig_instance(instance_id):
            self.create_rig_instance(instance_id)

        for shot_id, shot in ri.get_shots().items():
            cam = shot.camera
            if cam is not None and not self.has_camera(cam.id):
                self.create_camera(cam)

            rc = shot.get_rig_camera()
            if rc is not None and not self.has_rig_camera(rc.id):
                self.create_rig_camera(rc)

            exists = self.has_pano_shot(shot_id) if is_panoshot else self.has_shot(shot_id)
            if not exists:
                cam_id = cam.id if cam else ""
                rc_id  = rc.id  if rc  else ""
                if is_panoshot:
                    self.create_pano_shot(shot_id, cam_id, rc_id, instance_id, shot.pose)
                else:
                    self.create_shot(shot_id, cam_id, rc_id, instance_id, shot.pose)

        self.get_rig_instance(instance_id).update_instance_pose_with_shot(
            other_shot.id, other_shot.pose
        )

    # --- landmarks -----------------------------------------------------------

    def create_landmark(self, lm_id: str, global_pos: np.ndarray) -> Landmark:
        if lm_id in self._landmarks:
            raise RuntimeError(f"Landmark {lm_id} already exists.")
        lm = Landmark(lm_id, global_pos)
        self._landmarks[lm_id] = lm
        return lm

    def remove_landmark(self, lm):
        lm_id = lm.id if isinstance(lm, Landmark) else lm
        if lm_id not in self._landmarks:
            raise RuntimeError(f"Accessing invalid LandmarkId {lm_id}")
        landmark = self._landmarks[lm_id]
        for shot, feat_id in list(landmark.get_observations().items()):
            shot.remove_landmark_observation(feat_id)
        del self._landmarks[lm_id]

    def has_landmark(self, lm_id: str) -> bool:
        return lm_id in self._landmarks

    def get_landmark(self, lm_id: str) -> Landmark:
        if lm_id not in self._landmarks:
            raise RuntimeError(f"Accessing invalid LandmarkId {lm_id}")
        return self._landmarks[lm_id]

    def get_landmark_view(self) -> LandmarkView:
        return LandmarkView(self._landmarks)

    def get_landmarks(self) -> LandmarkView:
        return self.get_landmark_view()

    def clear_observations_and_landmarks(self):
        for lm in self._landmarks.values():
            for shot, feat_id in lm.get_observations().items():
                shot.remove_landmark_observation(feat_id)
            lm.clear_observations()
        self._landmarks.clear()

    def clean_landmarks_below_min_observations(self, min_observations: int):
        to_delete = [
            lm_id for lm_id, lm in self._landmarks.items()
            if lm.number_of_observations() < min_observations
        ]
        for lm_id in to_delete:
            self.remove_landmark(lm_id)

    # --- observations --------------------------------------------------------

    def add_observation(self, shot_or_id, landmark_or_id, obs: Observation):
        shot = shot_or_id if isinstance(shot_or_id, Shot) \
               else self.get_shot(shot_or_id)
        lm   = landmark_or_id if isinstance(landmark_or_id, Landmark) \
               else self.get_landmark(landmark_or_id)
        lm.add_observation(shot, obs.id)
        shot.create_observation(lm, obs)

    def remove_observation(self, shot_id: str, lm_id: str):
        shot = self.get_shot(shot_id)
        lm   = self.get_landmark(lm_id)
        feat_id = lm.get_observation_id_in_shot(shot)
        if feat_id is not None:
            shot.remove_landmark_observation(feat_id)
        lm.remove_observation(shot)

    # --- reference -----------------------------------------------------------

    # def set_reference(self, reference):
    #     self._reference = reference

    # SAU:
    def set_reference(self, lat_or_reference, lon=None, alt=None):

        if lon is None and alt is None:

            self._reference = lat_or_reference
        else:

            class _Ref:
                pass
            ref = _Ref()
            ref.lat = float(lat_or_reference)
            ref.lon = float(lon)
            ref.alt = float(alt)
            self._reference = ref

    def get_reference(self):
        return self._reference

    # --- reprojection errors -------------------------------------------------

    def compute_reprojection_errors(
        self, tracks_manager: TracksManager, error_type: ErrorType
    ) -> Dict[str, Dict[str, np.ndarray]]:
        errors: Dict[str, Dict[str, np.ndarray]] = {}
        for shot_id in tracks_manager.get_shot_ids():
            if shot_id not in self._shots:
                continue
            shot = self._shots[shot_id]
            per_shot: Dict[str, np.ndarray] = {}
            for track_id, obs in tracks_manager.get_shot_observations(shot_id).items():
                if track_id not in self._landmarks:
                    continue
                lm = self._landmarks[track_id]
                pt = lm.get_global_pos()
                if error_type == ErrorType.Pixel or error_type.value == 0:
                    per_shot[track_id] = obs.point - shot.project(pt)
                elif error_type == ErrorType.Normalized or error_type.value == 1:
                    per_shot[track_id] = (obs.point - shot.project(pt)) / obs.scale
                elif error_type == ErrorType.Angular or error_type.value == 2:
                    origin  = shot.pose.get_origin() if shot.pose else np.zeros(3)
                    pt_dir  = (pt - origin) / (np.linalg.norm(pt - origin) + 1e-10)
                    bearing = shot.bearing(obs.point)
                    bearing = bearing / (np.linalg.norm(bearing) + 1e-10)
                    angle   = np.arccos(np.clip(pt_dir.dot(bearing), -1.0, 1.0))
                    per_shot[track_id] = np.array([angle, angle])
            errors[shot_id] = per_shot
        return errors

    def get_valid_observations(
        self, tracks_manager: TracksManager
    ) -> Dict[str, Dict[str, Observation]]:
        result: Dict[str, Dict[str, Observation]] = {}
        for shot_id in tracks_manager.get_shot_ids():
            if shot_id not in self._shots:
                continue
            per_shot: Dict[str, Observation] = {}
            for track_id, obs in tracks_manager.get_shot_observations(shot_id).items():
                if track_id in self._landmarks:
                    per_shot[track_id] = obs
            result[shot_id] = per_shot
        return result

    def to_tracks_manager(self) -> TracksManager:
        tm = TracksManager()
        for shot_id, shot in {**self._shots, **self._pano_shots}.items():
            for lm, feat_id in shot.get_landmark_observations().items():
                obs = shot.get_landmark_observation(lm)
                if obs:
                    tm.add_observation(shot_id, lm.id, obs)
        return tm

    def __repr__(self):
        return (f"Map(cameras={len(self._cameras)}, shots={len(self._shots)}, "
                f"landmarks={len(self._landmarks)})")